const rawText = $input.first().json.content.parts[0].text; 
const name = $('cv-generation-start').first().json.body.fullName

// 2. Форматируем текст для HTML
let formattedText = rawText
  // Очищаем от случайных маркдаун-блоков, если LLM всё-таки их выдаст
  .replace(/```markdown/gi, '').replace(/```/gi, '').trim()
  // Заменяем жирный шрифт маркдауна на HTML
  .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
  // Заменяем двойные переносы строк на закрытие/открытие абзаца
  .replace(/\n\n/g, '</p><p>')
  // Заменяем оставшиеся одинарные переносы на <br>
  .replace(/\n/g, '<br>');

// Оборачиваем весь сгенерированный текст в начальный и конечный тег абзаца
formattedText = `<p>${formattedText}</p>`;

// 3. Собираем HTML-шаблон
const htmlString = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <style>
    /* Настройки страницы и шрифтов */
    body { 
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; 
      line-height: 1.6; 
      color: #222; 
      margin: 60px; /* Большие отступы для классического письма */
      font-size: 14px; 
    }

    /* Шапка письма (Letterhead) */
    .header {
      border-bottom: 2px solid #2c3e50;
      padding-bottom: 15px;
      margin-bottom: 40px;
    }
    .header h1 {
      margin: 0;
      font-size: 26px;
      text-transform: uppercase;
      letter-spacing: 1.5px;
      color: #111;
    }
    .header p {
      margin: 5px 0 0 0;
      font-size: 12px;
      color: #555;
    }

    /* Основной текст письма */
    .letter-body p {
      margin-bottom: 12px;
      text-align: justify; /* Выравнивание по ширине */
      text-indent: 2.5em; /* КРАСНАЯ СТРОКА для абзацев */
    }

    /* Убираем красную строку у первого абзаца (Приветствия "Dear Hiring Team...") */
    .letter-body p:first-of-type {
      text-indent: 0;
    }

    strong { 
      color: #000; 
    }

    /* Блок с подписью (без красной строки) */
    .sign-off {
      margin-top: 40px;
    }
    .sign-off p {
      margin: 0 0 5px 0;
      text-indent: 0; /* Здесь красная строка не нужна */
    }
    .contact-links {
      color: #555;
      font-size: 13px;
    }
    .contact-links a {
      color: #0066cc;
      text-decoration: none;
    }
  </style>
</head>
<body>

  <!-- Шапка письма -->
  <div class="header">
    <h1>Maxim Krendel</h1>
    <p>Senior Frontend Engineer | B.Sc. Information Systems, BGU</p>
  </div>

  <!-- Само тело письма, сгенерированное LLM -->
  <div class="letter-body">
    ${formattedText}
  </div>

  <!-- Жестко зашитая подпись и контакты (МОК) -->
  <div class="sign-off">
    <p>Sincerely,</p>
    <p style="margin-top: 20px;"><strong>${name}</strong></p>
  </div>

</body>
</html>`;

// 4. Конвертируем строку в буфер и отдаем n8n встроенным методом
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(htmlString, 'utf8'), 
  'index.html', 
  'text/html'
);

// 5. Возвращаем результат в формате файла
return [{
  json: { filename: 'cl.html' },
  binary: {
    data: binaryData}
}];

// 1. Достаём сырой ответ
let rawOutput = $input.first().json?.content?.parts?.[0]?.text 
             || $input.first().json?.text 
             || $input.first().json?.message?.content 
             || "";

rawOutput = rawOutput.replace(/^```(json|markdown|text)?/im, '').replace(/```$/m, '').trim();

let megaCvMarkdown = "";

// 2. УБЕР-ПАРСЕР: Ищет JSON даже если он внутри массива или текста
const jsonMatch = rawOutput.match(/(\[[\s\S]*\])|(\{[\s\S]*\})/); 
let isJsonParsed = false;

if (jsonMatch) {
  try {
    let parsed = JSON.parse(jsonMatch[0]);

    // Если ИИ обернул всё в массив [ { ... } ], достаем первый элемент
    if (Array.isArray(parsed)) {
      parsed = parsed[0];
    }

    // Вспомогательная функция: ищет ключ независимо от регистра (summary == Summary == SUMMARY)
    const getVal = (obj, keyName) => {
      if (!obj || typeof obj !== 'object') return null;
      const key = Object.keys(obj).find(k => k.toLowerCase() === keyName.toLowerCase());
      return key ? obj[key] : null;
    };

    const summary = getVal(parsed, 'summary');
    const skills = getVal(parsed, 'skills');
    const experience = getVal(parsed, 'experience');

    // Если нашли хотя бы один нужный блок, собираем Markdown
    if (summary || experience) {
      let builtMd = `### Summary\n${summary || ''}\n\n### Skills\n`;

      if (skills) {
        for (const [key, value] of Object.entries(skills)) {
          // Если ИИ прислал ключи с нижним подчеркиванием - делаем красиво. Если обычный текст - оставляем.
          let cleanKey = key.includes('_') 
            ? key.split('_').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ').replace(' And ', ' & ')
            : key;
          builtMd += `**${cleanKey}:** ${value}\n`;
        }
      }

      builtMd += `\n### Experience\n\n`;
      if (experience && Array.isArray(experience)) {
        experience.forEach(job => {
          // Достаем поля как бы ИИ их ни назвал
          const title = getVal(job, 'title') || getVal(job, 'role') || '';
          const company = getVal(job, 'company') || '';
          const dates = getVal(job, 'dates') || '';

          // Защита от склеивания (если ИИ засунул компанию в поле Role)
          let header = title;
          if (company && !title.includes(company)) {
            header += ` | ${company}`;
          }

          builtMd += `**${header}** | *${dates}*\n`;

          const bullets = getVal(job, 'bullets') || getVal(job, 'experience') || [];
          if (Array.isArray(bullets)) {
            bullets.forEach(b => builtMd += `* ${b.replace(/\n/g, ' ').trim()}\n`);
          }
          builtMd += `\n`;
        });
      }

      megaCvMarkdown = builtMd.trim();
      isJsonParsed = true;
    }
  } catch (e) {
    // Если JSON битый, молча падаем в запасной вариант (парсинг текста)
  }
}

// 3. Запасной вариант (если пришел чистый текст без JSON)
if (!isJsonParsed) {
  megaCvMarkdown = rawOutput.split(/(###\s*(Education|Languages)|EDUCATION\n)/i)[0].trim();
}

// 4. Достаем Base CV для статики (и далее по тексту вашего скрипта...)
const baseCv = $('cv-generation-start').first().json.body.baseCv;

function extractSection(text, sectionName) {
  const regex = new RegExp(`###\\s*${sectionName}\\s*\\n([\\s\\S]*?)(?=###|$)`, 'i');
  const match = text.match(regex);
  return match ? match[1].trim() : '';
}

function extractHeader(text) {
  const lines = text.trim().split('\n');
  const nameLine = lines.find(l => l.startsWith('#')) || lines[0];
  const contactLine = lines.find(l => l.includes('@') || l.includes('+')) || '';
  return { 
    name: nameLine.replace(/^#+\s*/, '').trim(), 
    contacts: contactLine.trim() 
  };
}

const education = extractSection(baseCv, 'Education');
const languages = extractSection(baseCv, 'Languages');
const { name, contacts } = extractHeader(baseCv);

// 5. Собираем финальный документ
const finalMarkdown = `# ${name}
**${contacts}**

---

${megaCvMarkdown}

### Education
${education}

### Languages
${languages}`;

// 6. Конвертируем Markdown в HTML
function markdownToHtml(md) {
  const lines = md.split(/\r?\n/);
  const html = [];
  let inList = false;

  for (let line of lines) {
    line = line.trim();

    if (!line) {
      if (inList) { html.push('</ul>'); inList = false; }
      continue;
    }

    line = line
      .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/\[(.*?)\]\((.*?)\)/g, '<a target="_blank" href="$2">$1</a>');

    if (line.startsWith('### ')) {
      if (inList) { html.push('</ul>'); inList = false; }
      html.push(`<h3>${line.substring(4)}</h3>`);
    } else if (line.startsWith('## ')) {
      if (inList) { html.push('</ul>'); inList = false; }
      html.push(`<h2>${line.substring(3)}</h2>`);
    } else if (line.startsWith('# ')) {
      if (inList) { html.push('</ul>'); inList = false; }
      html.push(`<h1>${line.substring(2)}</h1>`);
    } else if (line === '---') {
      if (inList) { html.push('</ul>'); inList = false; }
      html.push('<hr>');
    } else if (line.startsWith('* ') || line.startsWith('- ')) {
      if (!inList) { html.push('<ul>'); inList = true; }
      html.push(`<li>${line.substring(2)}</li>`);
    } else {
      if (inList) { html.push('</ul>'); inList = false; }
      if (html.length > 0 && html[html.length - 1].startsWith('<h1>')) {
        html.push(`<p class="contact-info">${line}</p>`);
      } else {
        html.push(`<p>${line}</p>`);
      }
    }
  }

  if (inList) html.push('</ul>');
  return html.join('\n');
}

// 7. Формируем HTML и бинарник
const htmlString = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
<style>
    /* Уменьшили только font-size, отступы (margin) и интервалы (line-height) остались оригинальными */
    body { font-family: Arial, Helvetica, sans-serif; line-height: 1.4; color: #222; margin: 40px; font-size: 11.5px; } /* Было 13px */
    h1 { text-align: center; margin: 0 0 5px 0; color: #000; font-size: 22px; letter-spacing: 0.5px; } /* Было 24px */
    .contact-info { text-align: center; font-size: 11px; color: #444; margin: 0 0 15px 0; } /* Было 12px */
    hr { border: none; border-top: 1px solid #ddd; margin: 15px 0; }
    h3 { border-bottom: 1px solid #333; padding-bottom: 2px; margin-top: 15px; margin-bottom: 8px; font-size: 13px; text-transform: uppercase; color: #111; } /* Было 14px */
    p { margin: 4px 0; }
    ul { margin: 4px 0 10px 0; padding-left: 20px; }
    li { margin-bottom: 4px; }
    a { color: #0056b3; text-decoration: none; }
    strong { color: #000; font-weight: 600; }
  </style>
</head>
<body>
${markdownToHtml(finalMarkdown)}
</body>
</html>`;

const binaryData = Buffer.from(htmlString, 'utf-8');

return [{
  json: { filename: 'resume.html' },
  binary: {
    data: await this.helpers.prepareBinaryData(binaryData, 'index.html', 'text/html')
  }
}];

// 1. Достаем сырой текст (поддерживает разные форматы выхода AI-нод)
const rawText = $input.first().json?.content?.parts?.[0]?.text 
             || $input.first().json?.text 
             || $input.first().json?.message?.content 
             || $input.first().json?.content
             || JSON.stringify($input.first().json);

if (!rawText) {
  return [{ json: { personal_note: "Ошибка: получен пустой ответ" } }];
}

// 2. Счищаем мусор, если ИИ обернул ответ в markdown-блоки
const cleanText = rawText.replace(/^```(json|text|markdown)?/im, '').replace(/```$/m, '').trim();

let finalMessage = "";

// 3. Пытаемся понять, JSON это или обычный текст
try {
  const parsedData = JSON.parse(cleanText);

  // Рекурсивный экстрактор: пробивает массивы и объекты до самой строки
  function extractString(data) {
    if (typeof data === 'string') return data;
    if (Array.isArray(data)) return extractString(data[0]); // Берем первый элемент массива
    if (typeof data === 'object' && data !== null) {
      // Ищем популярные ключи, которые любит выдумывать ИИ
      if (data.message) return extractString(data.message);
      if (data.note) return extractString(data.note);
      if (data.text) return extractString(data.text);

      // Если ключи другие, просто берем первое попавшееся значение
      return extractString(Object.values(data)[0]);
    }
    return String(data || '');
  }

  finalMessage = extractString(parsedData);

} catch (e) {
  // Если JSON.parse выдал ошибку, значит ИИ послушался и выдал чистый текст!
  finalMessage = cleanText;
}

// 4. Отдаем чистую строку в удобном ключе для отправки на ваш бэкенд
return [{
  json: {
    personal_note: finalMessage.trim()
  }
}];
